//-------------------------------------------------------------------------
scwin.f_openClntPopUp = function (pAllSearch) {
  var inObj = ed_clntNo;
  var pairObj = ed_clntNm;
  if (!scwin.f_canOpenPopUp(inObj, pairObj)) {
    return;
  }

  //디테일 수입 대표거래처 팝업
  udc_clnt.cfCommonPopUp(scwin.udc_clnt_callBackFunc // XML상의 SELECT ID	
  , $c.gus.cfGetValue($p, inObj) // 화면에서의 ??? Code Element의	Value
  , $c.gus.cfGetValue($p, pairObj) // 화면에서의 ??? Name Element의	Value
  , "T" // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
  , null // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
  , null // Title순서	
  , null // 보여주는 각 컬럼들의 폭	
  , null // 컬럼중에서 숨기는	컬럼 지정	
  , null // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
  , null // POP-UP뛰을때 원도우의	사용자 정의	폭
  , null // POP-UP뛰을때 우도우의	사용자 정의	높이	
  , null // 윈도우 위치 Y좌표	
  , null // 윈도우 위치 X좌표
  , null // 중복체크여부	("F")
  , 'F' // 전체검색허용여부	("F")
  , "대표거래처,거래처코드,거래처명" // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
  );
};
scwin.f_canOpenPopUp = function (inObj, pairObj) {
  if ($c.gus.cfIsNull($p, pairObj)) {
    if ($c.gus.cfGetValue($p, inObj) == "") {
      $c.gus.cfClearPairObj($p, inObj);
      $c.gus.cfSetHiddenValue($p, inObj, "");
      return false;
    }
    if ($c.gus.cfGetValue($p, inObj) == $c.gus.cfGetHiddenValue($p, inObj)) return false;
    return true;
  }
  return true;
};

