scwin.f_openPopUpText = function (gubun, nmObj, cdObj, pWinCloseTF) {
  var pCode = "";
  var pName = "";
  var pSelectID = "";
  var pWtitleSearch = "";
  var rtnList = new Array();
  var pWhere = null;
  pCode = cdObj.value;
  pName = nmObj.value;
  if (gubun == 1) {
    //청구처
    pSelectID = "retrieveClntInfo";
    pWtitleSearch = "청구처,청구처코드,청구처";
    pDispCnt = "5";
    pTitle = null;
  } else if (gubun == 3) {
    //매출부서	
    pSelectID = "retrieveLogisDeptInfo";
    pWtitleSearch = "매출부서,매출부서코드,매출부서";
    pTitle = null;
    pDispCnt = "2";
    pWhere = ",,,,,,1,";
  } else if (gubun == 5) {
    //청구부서	
    pSelectID = "retrieveLogisDeptInfo";
    pWtitleSearch = "청구부서,청구부서코드,청구부서";
    pTitle = null;
    pDispCnt = "2";
    pWhere = ",,,,,,,1";
  }
  rtnList = cfCommonPopUp(pSelectID,
  //pSelectID
  pCode,
  //pCode
  pName,
  //pName
  pWinCloseTF,
  //pWinCloseTF
  pDispCnt,
  //pDispCnt
  pTitle,
  //pTitle
  null,
  //pWidth
  null,
  //pHidden
  pWhere,
  //pWhere
  null,
  //pW
  null,
  //pH
  null,
  //pTop
  null,
  //pLeft
  null,
  //pExistTF - 중복체크여부	("F")
  null,
  //pAllSearchTF - 전체검색허용여부	("F")
  pWtitleSearch); //pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")

  if (rtnList != null) {
    if (rtnList[0] == "N/A") {
      //팝업에서 닫기버튼 클릭시	
      cfSetReturnValue(rtnList, cdObj, nmObj);
    } else {
      cdObj.value = rtnList[0];
      nmObj.value = rtnList[1];
      cdObj.hidVal = rtnList[0];
      nmObj.hidVal = rtnList[1];
    }
  } else {
    cfInitObjects([cdObj, nmObj]);
    cfInitHidVal([cdObj, nmObj]);
  }
};

