//-------------------------------------------------------------------------
// 생성 f_save
//-------------------------------------------------------------------------
scwin.btn_save_onClick = async function (e) {
  dma_common.set("bilgClntNo", ed_bilgClntNo.getValue());
  dma_common.set("bilgLodeptCd", ed_bilgLodeptCd.getValue());
  dma_common.set("selpchItemCd", ed_selpchItemCd.getValue());
  dma_common.set("trffClsCd", lc_trffClsCd.getValue());
  dma_common.set("sellLodeptCd", ed_sellLodeptCd.getValue());
  dma_common.set("rmk", ed_rmk.getValue());
  dma_common.set("rsltsStdDt", ica_rsltsStdDt.getValue());
  dma_common.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());
  dma_common.set("odrNo", lc_odrNo.getValue());
  dma_common.set("clntNo_cond", ed_clntNo.getValue());
  dma_common.set("transClsCd", acb_transClsCd.getValue());
  dma_common.set("vsslCnt", ed_vsslCnt.getValue());
  dma_common.set("blNo", ed_blNo.getValue());
  dma_common.set("stConfirmDate", ica_stConfirmDate.getValue());
  dma_common.set("edConfirmDate", ica_edConfirmDate.getValue());
  dma_common.set("confirmYn", "");
  dma_common.set("createYn", acb_createYn.getValue());
  if (ds_master.getTotalRow() == 0) {
    $c.win.alert($p, MSG_CM_WRN_002);
    return;
  }
  if (!(await $c.gus.cfValidate($p, [regData]))) return;
  if (dma_common.get("trffClsCd") == "01" && acb_transClsCd.getValue() == "") {
    $c.win.alert($p, "운송 매출은 운송 구분을 MIP/기아(MIP)로 선조회 한 후 생성이 가능합니다.");
    return false;
  }
  if (dma_common.get("trffClsCd") == "01" && dma_common.get("selpchItemCd") != "0010") {
    $c.win.alert($p, "매출 구분이 운송료(매출)인 경우, 매출항목은 운송료로 선택해 주세요.");
    return false;
  }
  if (dma_common.get("trffClsCd") == "02" && dma_common.get("selpchItemCd") != "0029") {
    $c.win.alert($p, "매출 구분이 보관료인 경우, 매출항목은 기본보관료로 선택해 주세요.");
    return false;
  }
  for (i = 0; i < ds_master.getTotalRow(); i++) {
    if (dma_common.get("trffClsCd") == "01" && ds_master.getCellData(i, "transSellAmt") > 0) {
      $c.win.alert($p, i + 1 + "번째 코일의 운송 매출이 이미 생성되었습니다.");
      return false;
    }
    if (dma_common.get("trffClsCd") == "02" && ds_master.getCellData(i, "storeSellAmt") > 0) {
      $c.win.alert($p, i + 1 + "번째 코일의 보관 매출이 이미 생성되었습니다.");
      return false;
    }
    if (dma_common.get("trffClsCd") == "01" && ds_master.getCellData(i, "confirmYn") != "2") {
      $c.win.alert($p, i + 1 + "번째 코일의 운송 매출은 생성할 수 없습니다./br출고완료 해주시기 바랍니다.");
      return false;
    }
  }
  if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
    $c.sbm.execute($p, sbm_master);
  }
};

